const WA = "33758821956";
const EIMG = "data:image/jpeg;base64,";
let cart = [], mO = false;

/* ═══ AGE GATE ═══ */
function acceptAge() {
  localStorage.setItem('age_ok', Date.now());
  const g = document.getElementById('ageGate');
  g.classList.add('hidden');
  setTimeout(() => { g.style.display='none'; document.body.classList.remove('locked'); }, 500);
}
function rejectAge() {
  document.body.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:100vh;background:#0F0F0F;color:#fff;text-align:center;font-family:Figtree,sans-serif;padding:2rem"><div><h1 style="font-family:Bebas Neue,cursive;font-size:3rem;margin-bottom:1rem">Accès refusé</h1><p style="opacity:.6">Notre site est réservé aux personnes majeures.</p></div></div>';
}
(function(){
  const t = localStorage.getItem('age_ok');
  if(t && Date.now()-parseInt(t) < 30*24*60*60*1000) {
    document.getElementById('ageGate').style.display='none';
    document.body.classList.remove('locked');
  }
})();

/* ═══ NAV ═══ */
function go(id) {
  document.querySelectorAll('.pg').forEach(p=>p.classList.remove('ac'));
  document.getElementById('pg-'+id).classList.add('ac');
  document.querySelectorAll('.nul a').forEach(a=>a.classList.remove('ac'));
  const a=document.getElementById('a-'+id); if(a) a.classList.add('ac');
  window.scrollTo({top:0,behavior:'smooth'});
  document.getElementById('mnv').classList.remove('op');
  document.getElementById('ham').classList.remove('op');
  mO=false;
}
function tM() {
  mO=!mO;
  document.getElementById('mnv').classList.toggle('op',mO);
  document.getElementById('ham').classList.toggle('op',mO);
}
window.addEventListener('scroll',()=>document.getElementById('nav').classList.toggle('sc',scrollY>10));

/* ═══ QUANTITY +/− ═══ */
function chgQ(btn, d) {
  const ctrl = btn.closest('.qty-ctrl');
  const span = ctrl.querySelector('.qty-n');
  const val = Math.max(1, Math.min(99, parseInt(span.textContent)+d));
  span.textContent = val;
  // Update displayed unit/box price (no discount here — discount is on cart total)
  const card = btn.closest('.pc');
  const pb = parseFloat(card.dataset.pb);
  const box = parseInt(card.dataset.box);
  const u = parseFloat(card.dataset.u);
  card.querySelector('[data-out="u"]').textContent = u.toFixed(2).replace('.',',')+'€';
  card.querySelector('[data-out="b"]').textContent = pb.toFixed(2).replace('.',',')+'€';
}

/* ═══ FLAVOR PICKER ═══ */
let fpCard=null, fpFlav=[], fpCat='all';
const fpOv=document.getElementById('fpOv');
const fpList=document.getElementById('fpList');
const fpFt=document.getElementById('fpFt');

function openFP(btn) {
  fpCard = btn.closest('.pc');
  const raw = fpCard.dataset.flavors;
  const tmp = document.createElement('textarea'); tmp.innerHTML=raw;
  fpFlav = JSON.parse(tmp.value);
  document.getElementById('fpModel').textContent = fpCard.dataset.model;
  document.getElementById('fpSI').value='';
  document.getElementById('fpSX').classList.remove('sh');
  fpCat='all';
  document.querySelectorAll('.fp-qf').forEach(q=>q.classList.remove('on'));
  document.querySelector('.fp-qf').classList.add('on');
  renderFP();
  fpOv.classList.add('op');
  document.body.style.overflow='hidden';
  setTimeout(()=>document.getElementById('fpSI').focus(),300);
}
function closeFP() {
  fpOv.classList.remove('op');
  document.body.style.overflow='';
  fpCard=null;
}
function setQF(btn,cat) {
  document.querySelectorAll('.fp-qf').forEach(q=>q.classList.remove('on'));
  btn.classList.add('on'); fpCat=cat; renderFP();
}
function renderFP() {
  const q = document.getElementById('fpSI').value.toLowerCase().trim();
  document.getElementById('fpSX').classList.toggle('sh', q.length>0);
  const filtered = fpFlav.filter(f => {
    if(fpCat!=='all' && !(f.cats||[]).includes(fpCat)) return false;
    return !q || f.name.toLowerCase().includes(q);
  });
  fpList.innerHTML = filtered.length===0
    ? '<div class="fp-empty">🔍 Aucun goût trouvé<br><span style="font-size:.78rem;opacity:.6">Essaie un autre mot</span></div>'
    : filtered.map(f=>`<div class="fp-item" onclick="pickFlavor('${f.name.replace(/'/g,"\\'")}','${f.emoji}')"><span class="fp-item-name">${f.name}</span><span class="fp-item-emoji">${f.emoji}</span></div>`).join('');
  fpFt.textContent = filtered.length+' / '+fpFlav.length+' goûts';
}
function pickFlavor(name,emoji) {
  if(!fpCard) return;
  const btn = fpCard.querySelector('.flv-btn');
  btn.classList.add('sel');
  btn.querySelector('.flv-cur').textContent = name+' '+emoji;
  fpCard.dataset.selFlavor = name;
  fpCard.dataset.selEmoji = emoji;
  closeFP();
  toast('✅ Goût sélectionné');
}

/* ═══ CART — GLOBAL DISCOUNT LOGIC ═══ */
function getTier(totalBoxes) {
  if(totalBoxes>=50) return {rate:.20, pct:20, label:'−20%', cls:'pill-20'};
  if(totalBoxes>=30) return {rate:.15, pct:15, label:'−15%', cls:'pill-15'};
  if(totalBoxes>=10) return {rate:.10, pct:10, label:'−10%', cls:'pill-10'};
  if(totalBoxes>=5)  return {rate:.05, pct:5,  label:'−5%',  cls:'pill-5'};
  return {rate:0, pct:0, label:'Aucune remise', cls:'pill-0'};
}
function nextTier(totalBoxes) {
  if(totalBoxes<5)  return {need:5-totalBoxes,  pct:5};
  if(totalBoxes<10) return {need:10-totalBoxes, pct:10};
  if(totalBoxes<30) return {need:30-totalBoxes, pct:15};
  if(totalBoxes<50) return {need:50-totalBoxes, pct:20};
  return null;
}

function addCart(btn, model, imgSrc) {
  const card = btn.closest('.pc');
  const flavor = card.dataset.selFlavor;
  const emoji  = card.dataset.selEmoji||'';
  if(!flavor) { toast('⚠️ Choisis un goût !'); return; }
  const qty = parseInt(card.querySelector('.qty-n').textContent);
  const pb  = parseFloat(card.dataset.pb);
  const u   = parseFloat(card.dataset.u);
  cart.push({id:Date.now(), model, flavor:flavor+' '+emoji, qty, pb, u, imgSrc});
  renderCart();
  toast('✅ '+model+' ajouté !');
  if(window.innerWidth>768) openCart();
}

function rmItem(id) { cart=cart.filter(i=>i.id!==id); renderCart(); }

function renderCart() {
  const totalBoxes = cart.reduce((a,i)=>a+i.qty, 0);
  const rawTotal   = cart.reduce((a,i)=>a+(i.pb*i.qty), 0);
  const tier       = getTier(totalBoxes);
  const discount   = rawTotal*tier.rate;
  const finalTotal = rawTotal-discount;
  const next       = nextTier(totalBoxes);

  // Nav badge
  document.getElementById('nbb').textContent = totalBoxes;

  // Discount bar
  const bar = document.getElementById('cartDiscountBar');
  if(cart.length>0) {
    const nextMsg = next
      ? `<div class="cdb-next">➕ Encore <strong>${next.need} boîte(s)</strong> pour −${next.pct}% sur tout le panier</div>`
      : `<div class="cdb-next" style="color:var(--grn)">🎉 Remise maximale −20% débloquée !</div>`;
    const savMsg = discount>0
      ? `<div class="cdb-saving">💰 Tu économises ${discount.toFixed(2).replace('.',',')} € sur cette commande</div>`
      : '';
    bar.innerHTML = `
      <div class="cart-discount-bar">
        <div class="cdb-top">
          <div class="cdb-total">${totalBoxes} boîte(s) au total</div>
          <span class="cdb-pill ${tier.cls}">${tier.label}</span>
        </div>
        ${savMsg}
        ${nextMsg}
      </div>`;
  } else {
    bar.innerHTML = '';
  }

  // Cart items
  const f = v => v.toFixed(2).replace('.',',')+' €';
  document.getElementById('cRaw').textContent   = f(rawTotal);
  document.getElementById('cTot').textContent   = f(finalTotal);
  document.getElementById('cShip').textContent  = finalTotal>=30?'🎉 Gratuite !':'Gratuite dès 30€';

  const savRow = document.getElementById('cSavRow');
  if(discount>0) {
    savRow.style.display='flex';
    document.getElementById('cSav').textContent = '−'+discount.toFixed(2).replace('.',',')+' €';
  } else {
    savRow.style.display='none';
  }

  // Items list
  document.getElementById('cdb').innerHTML = cart.length===0
    ? `<div class="cdem"><img src="${EIMG}" alt=""><p>Ton panier est vide !</p></div>`
    : cart.map(i=>{
        const sub = (i.pb*i.qty);
        const subD = sub*(1-tier.rate);
        return `<div class="ci">
          <img class="cii" src="${i.imgSrc}" alt="${i.model}">
          <div class="cin">
            <div class="cim">${i.model}</div>
            <div class="cid">${i.flavor}</div>
            <div class="cip">${i.qty} boîte(s) × ${i.pb.toFixed(2).replace('.',',')}€ = ${subD.toFixed(2).replace('.',',')} €${tier.rate>0?' <span style="text-decoration:line-through;opacity:.45;font-size:.7rem">'+sub.toFixed(2).replace('.',',')+'€</span>':''} </div>
          </div>
          <button class="crm" onclick="rmItem(${i.id})">✕</button>
        </div>`;
      }).join('');
}

function openCart()  { document.getElementById('cdr').classList.add('op'); document.getElementById('ov').classList.add('op'); }
function closeCart() { document.getElementById('cdr').classList.remove('op'); document.getElementById('ov').classList.remove('op'); }

/* ═══ CHECKOUT ═══ */
function openCheckout() {
  if(!cart.length) { toast('⚠️ Panier vide !'); return; }
  const totalBoxes = cart.reduce((a,i)=>a+i.qty,0);
  const raw = cart.reduce((a,i)=>a+(i.pb*i.qty),0);
  const tier = getTier(totalBoxes);
  const disc = raw*tier.rate;
  const final = raw-disc;
  const f = v => v.toFixed(2).replace('.',',')+'€';
  let sum = `<div class="csr"><span>Boîtes</span><span>${totalBoxes}</span></div>
    <div class="csr"><span>Sous-total brut</span><span>${f(raw)}</span></div>`;
  if(disc>0) sum += `<div class="csr sv"><span>Remise ${tier.label}</span><span>−${f(disc)}</span></div>`;
  sum += `<div class="csr"><span>Livraison</span><span>${final>=30?'Gratuite ✅':'À voir'}</span></div>
    <div class="csr big"><span>Total TTC</span><span>${f(final)}</span></div>`;
  document.getElementById('chkSum').innerHTML=sum;
  document.getElementById('chkmod').classList.add('op');
  closeCart();
}
function closeCheckout() { document.getElementById('chkmod').classList.remove('op'); }
function vf(id) { const el=document.getElementById(id); if(!el.value.trim()){el.classList.add('err');return false;} el.classList.remove('err');return true; }

function sendWA() {
  const req=['fPrenom','fNom','fTel','fAddr','fCp','fVille'];
  let ok=true; req.forEach(id=>{if(!vf(id))ok=false;});
  if(!ok){toast('⚠️ Remplis les champs obligatoires');return;}
  const v=id=>document.getElementById(id).value.trim();
  const totalBoxes=cart.reduce((a,i)=>a+i.qty,0);
  const raw=cart.reduce((a,i)=>a+(i.pb*i.qty),0);
  const tier=getTier(totalBoxes);
  const disc=raw*tier.rate;
  const final=raw-disc;
  const f=v=>v.toFixed(2).replace('.',',')+'€';
  let msg=`🛒 *NOUVELLE COMMANDE — SHOP TA PUFF*\n\n`;
  msg+=`👤 *CLIENT*\n${v('fPrenom')} ${v('fNom')}\n📞 ${v('fTel')}\n`;
  if(v('fEmail')) msg+=`📧 ${v('fEmail')}\n`;
  msg+=`\n📦 *LIVRAISON*\n${v('fAddr')}\n${v('fCp')} ${v('fVille')}\n`;
  msg+=`\n🛍️ *COMMANDE*\n`;
  cart.forEach((i,idx)=>{
    msg+=`\n${idx+1}. *${i.model}*\n   Goût : ${i.flavor}\n   Quantité : ${i.qty} boîte(s) × ${f(i.pb)}\n`;
  });
  msg+=`\n💰 *RÉCAPITULATIF*\n`;
  msg+=`Total boîtes : ${totalBoxes}\n`;
  msg+=`Sous-total brut : ${f(raw)}\n`;
  if(disc>0) msg+=`Remise ${tier.label} : −${f(disc)}\n`;
  msg+=`Livraison : ${final>=30?'Gratuite ✅':'À confirmer'}\n`;
  msg+=`*TOTAL FINAL : ${f(final)}*\n`;
  if(v('fNote')) msg+=`\n📝 ${v('fNote')}\n`;
  msg+=`\n✅ Commande client +18 ans`;
  window.open(`https://wa.me/${WA}?text=${encodeURIComponent(msg)}`,'_blank');
  toast('🚀 Redirection WhatsApp...');
  setTimeout(()=>{cart=[];renderCart();closeCheckout();},1500);
}

/* ═══ FILTERS ═══ */
function fi(btn,s,brand) {
  btn.closest('.fbr').querySelectorAll('.fc2').forEach(c=>c.classList.remove('on'));
  btn.classList.add('on');
  let n=0;
  document.querySelectorAll('#gr-'+brand+' .pc').forEach(c=>{
    const show=s==='all'||c.dataset.s===s;
    c.style.display=show?'':'none'; if(show)n++;
  });
  const cnt=document.getElementById('cn-'+brand);
  if(cnt) cnt.textContent=n+' produit'+(n>1?'s':'');
}

function toast(msg) {
  const t=document.getElementById('tst');
  t.textContent=msg; t.classList.add('sh');
  clearTimeout(t._t); t._t=setTimeout(()=>t.classList.remove('sh'),3000);
}

renderCart();
